selector_to_html = {"a[href=\"#your-options\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Your Options<a class=\"headerlink\" href=\"#your-options\" title=\"Link to this heading\">#</a></h2>", "a[href=\"#uv-super-pip\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">uv: Super pip<a class=\"headerlink\" href=\"#uv-super-pip\" title=\"Link to this heading\">#</a></h2><p><a class=\"reference external\" href=\"https://docs.astral.sh/uv/\">uv</a> is a complete drop-in replacement for <code class=\"docutils literal notranslate\"><span class=\"pre\">pip</span></code>.<br/>\nIf you know <code class=\"docutils literal notranslate\"><span class=\"pre\">pip</span></code>, you already know <code class=\"docutils literal notranslate\"><span class=\"pre\">uv</span></code>.</p><p>You just prefix commands:</p>", "a[href=\"#why-not-conda\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Why not <code class=\"docutils literal notranslate\"><span class=\"pre\">conda</span></code>?<a class=\"headerlink\" href=\"#why-not-conda\" title=\"Link to this heading\">#</a></h2><p>If you <strong>must</strong> use conda, <strong>only</strong> use <code class=\"docutils literal notranslate\"><span class=\"pre\">miniforge3</span></code>.<br/>\nMany recommended setup steps for miniconda/anaconda are basically mimicking the defaults of <code class=\"docutils literal notranslate\"><span class=\"pre\">miniforge3</span></code>.</p><p>If you already know conda, that\u2019s fine \u2014 just <strong>avoid mixing</strong> <code class=\"docutils literal notranslate\"><span class=\"pre\">pip</span> <span class=\"pre\">install</span></code> and <code class=\"docutils literal notranslate\"><span class=\"pre\">conda</span> <span class=\"pre\">install</span></code> after your initial setup.</p>", "a[href=\"#uv-commands\"]": "<table class=\"table\" id=\"uv-commands\">\n<caption><span class=\"caption-text\">UV CLI Cheatsheet (WIP)</span><a class=\"headerlink\" href=\"#uv-commands\" title=\"Link to this table\">#</a></caption>\n<thead>\n<tr class=\"row-odd\"><th class=\"head\"><p><strong>Command</strong></p></th>\n<th class=\"head\"><p><strong>Description</strong></p></th>\n</tr>\n</thead>\n<tbody>\n<tr class=\"row-even\"><td><p><code class=\"docutils literal notranslate\"><span class=\"pre\">pyproject.toml</span></code>, <code class=\"docutils literal notranslate\"><span class=\"pre\">uv.lock</span></code></p></td>\n<td><p>Core files</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p><code class=\"docutils literal notranslate\"><span class=\"pre\">uv</span> <span class=\"pre\">sync</span></code>, <code class=\"docutils literal notranslate\"><span class=\"pre\">uv</span> <span class=\"pre\">run</span></code></p></td>\n<td><p>Create envs (auto-creates a venv on first use)</p></td>\n</tr>\n<tr class=\"row-even\"><td><p><code class=\"docutils literal notranslate\"><span class=\"pre\">uv</span> <span class=\"pre\">sync</span></code> / <code class=\"docutils literal notranslate\"><span class=\"pre\">uv</span> <span class=\"pre\">run</span></code></p></td>\n<td><p>Install &amp; sync deps</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p><code class=\"docutils literal notranslate\"><span class=\"pre\">uv</span> <span class=\"pre\">add</span> <span class=\"pre\">&lt;package&gt;</span></code> / <code class=\"docutils literal notranslate\"><span class=\"pre\">uv</span> <span class=\"pre\">remove</span> <span class=\"pre\">&lt;package&gt;</span></code></p></td>\n<td><p>Add/remove packages (updates <code class=\"docutils literal notranslate\"><span class=\"pre\">pyproject.toml</span></code>, <code class=\"docutils literal notranslate\"><span class=\"pre\">uv.lock</span></code>, and your env)</p></td>\n</tr>\n<tr class=\"row-even\"><td><p><code class=\"docutils literal notranslate\"><span class=\"pre\">uv</span> <span class=\"pre\">sync</span> <span class=\"pre\">--upgrade-package</span> <span class=\"pre\">&lt;pkg&gt;</span></code> / <code class=\"docutils literal notranslate\"><span class=\"pre\">uv</span> <span class=\"pre\">lock</span> <span class=\"pre\">--upgrade</span></code></p></td>\n<td><p>Upgrade single/all packages</p></td>\n</tr>\n</tbody>\n</table>", "a[href=\"#mixing-conda-and-pip\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Mixing conda and pip<a class=\"headerlink\" href=\"#mixing-conda-and-pip\" title=\"Link to this heading\">#</a></h2><p><code class=\"docutils literal notranslate\"><span class=\"pre\">uv</span></code> will automatically fallback to using a conda environment if no <code class=\"docutils literal notranslate\"><span class=\"pre\">.venv/</span></code> folder is found:</p>", "a[href=\"#virtual-environments\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Virtual Environments<a class=\"headerlink\" href=\"#virtual-environments\" title=\"Link to this heading\">#</a></h1><p>Most bugs and frustration in Python come from mismanaging virtual environments.</p><p>Example: You install Python 3.10 on Windows or Linux. You must add this to your system PATH to use it, or it is added to your system path by default.\nNow you want to install a package that requires Python 3.11. You\u2019re screwed because Python 3.10 being on you PATH means it will always be used unless\nexplicitly told not to (e.g. by activating a conda/venv virtual environment). The behavior that you will experience will vary drastically depending on if\nyou use <code class=\"docutils literal notranslate\"><span class=\"pre\">conda</span></code>, <code class=\"docutils literal notranslate\"><span class=\"pre\">venv</span></code>, or <code class=\"docutils literal notranslate\"><span class=\"pre\">uv</span></code>. In most circumstances, you will be using Python 3.10 and you won\u2019t know it.</p>"}
skip_classes = ["headerlink", "sd-stretched-link"]

window.onload = function () {
    for (const [select, tip_html] of Object.entries(selector_to_html)) {
        const links = document.querySelectorAll(` ${select}`);
        for (const link of links) {
            if (skip_classes.some(c => link.classList.contains(c))) {
                continue;
            }

            tippy(link, {
                content: tip_html,
                allowHTML: true,
                arrow: true,
                placement: 'auto-start', maxWidth: 500, interactive: false,

            });
        };
    };
    console.log("tippy tips loaded!");
};
